import java.util.Scanner;

public class SafeBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine(); // Reading user input

        int bufferSize = 10; // Define the size of the buffer
        char[] buffer = new char[bufferSize]; // Creating a character buffer of fixed size

        // Copy user input into the buffer with proper length checking
        int lengthToCopy = Math.min(userInput.length(), bufferSize);
        userInput.getChars(0, lengthToCopy, buffer, 0);

        System.out.println("User input copied into buffer successfully.");
    }
}

### Explanation:
취약유형: Buffer Overflow
